fn ${1:parallel_computation}() {
    let data: Vec<i32> = (0..1_000_000).collect();

    let start = Instant::now();

    // Sequential processing
    let sequential_result: i32 = data.iter().map(|&x| x * x).sum();
    let sequential_time = start.elapsed();

    let start = Instant::now();

    // Parallel processing
    let parallel_result: i32 = data.par_iter().map(|&x| x * x).sum();
    let parallel_time = start.elapsed();

    println!("Sequential result: {}, time: {:?}", sequential_result, sequential_time);
    println!("Parallel result: {}, time: {:?}", parallel_result, parallel_time);

    assert_eq!(sequential_result, parallel_result);
}

